import { buildMatchFn } from "../../_lib/buildMatchFn.mjs";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.mjs";

const matchOrdinalNumberPattern = /^(\d+)(-?(械|泄|褦|邪|褟))?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^((写芯 )?薪\.?\s?械\.?)/i,
  abbreviated: /^((写芯 )?薪\.?\s?械\.?)/i,
  wide: /^(写芯 薪邪褕芯褩 械褉懈|薪邪褕芯褩 械褉懈|薪邪褕邪 械褉邪)/i,
};

const parseEraPatterns = {
  any: [/^写/i, /^薪/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,
  abbreviated: /^[1234](-?[懈褨]?泄?)? 泻胁.?/i,
  wide: /^[1234](-?[懈褨]?泄?)? 泻胁邪褉褌邪谢/i,
};

const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^[褋谢斜泻褌褔胁卸谐]/i,
  abbreviated:
    /^(褋褨褔|谢褞褌|斜械褉(械蟹)?|泻胁褨褌|褌褉邪胁|褔械褉胁|谢懈锌|褋械褉锌|胁械褉(械褋)?|卸芯胁褌|谢懈褋(褌芯锌)?|谐褉褍写)\.?/i,
  wide: /^(褋褨褔械薪褜|褋褨褔薪褟|谢褞褌懈泄|谢褞褌芯谐芯|斜械褉械蟹械薪褜|斜械褉械蟹薪褟|泻胁褨褌械薪褜|泻胁褨褌薪褟|褌褉邪胁械薪褜|褌褉邪胁薪褟|褔械褉胁薪褟|褔械褉胁械薪褜|谢懈锌械薪褜|谢懈锌薪褟|褋械褉锌械薪褜|褋械褉锌薪褟|胁械褉械褋械薪褜|胁械褉械褋薪褟|卸芯胁褌械薪褜|卸芯胁褌薪褟|谢懈褋褌芯锌邪写[邪]?|谐褉褍写械薪褜|谐褉褍写薪褟)/i,
};

const parseMonthPatterns = {
  narrow: [
    /^褋/i,
    /^谢/i,
    /^斜/i,
    /^泻/i,
    /^褌/i,
    /^褔/i,
    /^谢/i,
    /^褋/i,
    /^胁/i,
    /^卸/i,
    /^谢/i,
    /^谐/i,
  ],

  any: [
    /^褋褨/i,
    /^谢褞/i,
    /^斜/i,
    /^泻/i,
    /^褌/i,
    /^褔/i,
    /^谢懈锌/i,
    /^褋械/i,
    /^胁/i,
    /^卸/i,
    /^谢懈褋/i,
    /^谐/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[薪锌胁褋褔]/i,
  short: /^(薪写|锌薪|胁褌|褋褉|褔褌|锌褌|褋斜)\.?/i,
  abbreviated: /^(薪械写|锌芯薪|胁褨胁|褋械褉|褔械?褌胁|锌褌薪?|褋褍斜)\.?/i,
  wide: /^(薪械写褨谢[褟褨]|锌芯薪械写褨谢[芯泻][泻邪]|胁褨胁褌芯褉[芯泻][泻邪]|褋械褉械写[邪懈]|褔械褌胁械褉(谐邪)?|锌\W*?褟褌薪懈褑[褟褨]|褋褍斜芯褌[邪懈])/i,
};

const parseDayPatterns = {
  narrow: [/^薪/i, /^锌/i, /^胁/i, /^褋/i, /^褔/i, /^锌/i, /^褋/i],
  any: [/^薪/i, /^锌[芯薪]/i, /^胁/i, /^褋[械褉]/i, /^褔/i, /^锌\W*?[褟褌]/i, /^褋[褍斜]/i],
};

const matchDayPeriodPatterns = {
  narrow: /^([写锌]锌|锌褨胁薪\.?|锌芯谢\.?|褉邪薪芯泻|褉邪薪泻褍|写械薪褜|写薪褟|胁械褔\.?|薪褨褔|薪芯褔褨)/i,
  abbreviated: /^([写锌]锌|锌褨胁薪\.?|锌芯谢\.?|褉邪薪芯泻|褉邪薪泻褍|写械薪褜|写薪褟|胁械褔\.?|薪褨褔|薪芯褔褨)/i,
  wide: /^([写锌]锌|锌褨胁薪褨褔|锌芯谢褍写械薪褜|褉邪薪芯泻|褉邪薪泻褍|写械薪褜|写薪褟|胁械褔褨褉|胁械褔芯褉邪|薪褨褔|薪芯褔褨)/i,
};

const parseDayPeriodPatterns = {
  any: {
    am: /^写锌/i,
    pm: /^锌锌/i,
    midnight: /^锌褨胁薪/i,
    noon: /^锌芯谢/i,
    morning: /^褉/i,
    afternoon: /^写[械薪]/i,
    evening: /^胁/i,
    night: /^薪/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
